import numpy as np

def solve(grid):
    rows, cols = len(grid), len(grid[0])
    result = np.zeros((rows, cols), dtype=int)

    # Fill the first row and column manually
    for i in range(rows):
        if i == 0:
            result[i, :cols] = grid[i, :]
        else:
            result[i, :cols] = (result[i - 1, :cols] + grid[i, :cols]) % 10

    # Fill the rest of the matrix
    for i in range(1, rows):
        for j in range(1, cols):
            result[i, j] = (result[i - 1, j] + result[i, j - 1] + grid[i, j]) % 10

    return result.tolist()

