def solve(grid):
    """Apply the convolution rule repeatedly until no further changes occur."""
    def convolve(matrix):
        """Convolve the matrix with an identity matrix for modulo 10 operation."""
        return (matrix + np.eye(matrix.shape[0])) % 10

    while True:
        new_grid = convolve(grid)
        if np.array_equal(new_grid, grid):
            break
        grid = new_grid

    return new_grid.tolist()

